"use client";

import {
  PopoverTrigger as TooltipTrigger,
  type PopoverTriggerProps as TooltipTriggerProps,
  type PopoverTriggerRenderProps as TooltipTriggerRenderProps,
} from "../popover/popover-trigger";
import { type TooltipProps, TooltipRoot } from "./tooltip";
import { TooltipContent, type TooltipContentProps } from "./tooltip-content";

/** Root - manages hover state, delay, and enabled toggle. */
const Tooltip = Object.assign(TooltipRoot, {
  Trigger: TooltipTrigger,
  Content: TooltipContent,
});

export { Tooltip, type TooltipProps };
export {
  TooltipTrigger,
  TooltipContent,
  type TooltipTriggerProps,
  type TooltipTriggerRenderProps,
  type TooltipContentProps,
};

"use client";

import type { ReactNode } from "react";
import { PopoverRoot } from "../popover/popover";
import { PopoverTrigger } from "../popover/popover-trigger";
import { TooltipContent } from "./tooltip-content";

/** Props for tooltip. */
export interface TooltipProps {
  /** Trigger element (shorthand mode) or full Tooltip.Trigger/Tooltip.Content composition. */
  children: ReactNode;
  /**
   * Shorthand: when set, Tooltip renders children inside Tooltip.Trigger and content inside
   * Tooltip.Content automatically. When omitted, compose Tooltip.Trigger and Tooltip.Content
   * explicitly via children.
   */
  content?: ReactNode;
  /** Disables hover/focus triggering when false (use to suppress tooltips conditionally). */
  enabled?: boolean;
  /** Show delay after pointer enters the trigger; keyboard focus opens immediately. */
  delayMs?: number;
  /** Hide delay after pointer/focus leaves the trigger or content. */
  closeDelayMs?: number;
  /** Controlled open state. */
  open?: boolean;
  /** Initial open state for uncontrolled mode. */
  defaultOpen?: boolean;
  /** Fired when the open state changes. */
  onOpenChange?: (open: boolean) => void;
}

/** Root - manages hover state, delay, and enabled toggle. */
export function TooltipRoot({
  children,
  content,
  enabled = true,
  delayMs = 500,
  closeDelayMs,
  open,
  defaultOpen,
  onOpenChange,
}: TooltipProps) {
  return (
    <PopoverRoot
      triggerMode="hover"
      enabled={enabled}
      delayMs={delayMs}
      closeDelayMs={closeDelayMs}
      open={open}
      defaultOpen={defaultOpen}
      onOpenChange={onOpenChange}
    >
      {content != null ? (
        <>
          <PopoverTrigger>{children}</PopoverTrigger>
          <TooltipContent>{content}</TooltipContent>
        </>
      ) : (
        children
      )}
    </PopoverRoot>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { PopoverContent, type PopoverContentProps } from "../popover/popover-content";

/** Props for tooltip content. */
export interface TooltipContentProps extends Omit<PopoverContentProps, "autoFocus"> {}

/** Portal-rendered positioned content. */
export function TooltipContent({
  children,
  side = "top",
  align = "center",
  sideOffset = 4,
  className,
  ...rest
}: TooltipContentProps) {
  return (
    <PopoverContent
      side={side}
      align={align}
      sideOffset={sideOffset}
      data-slot="tooltip-content"
      className={cn(
        "max-w-xs border border-border bg-background px-2 py-1 font-mono text-xs text-foreground shadow-md",
        className,
      )}
      {...rest}
    >
      {children}
    </PopoverContent>
  );
}
